import java.util.concurrent.atomic.AtomicInteger;
public class Main {
    public static void main(String[] args) throws Exception {
        ThreadPool pool = new ThreadPool(new PoolConfig(2, 4, 10, 1000));
        AtomicInteger c = new AtomicInteger();
        for (int i = 0; i < 5; i++) {
            pool.submit(new Task() {
                public String getName() { return "T"; }
                public void execute() { try { Thread.sleep(20); } catch (Exception e) {} c.incrementAndGet(); }
            });
        }
        pool.shutdown();
        System.out.println("OK_BASIC=" + c.get());
    }
}

/* Test driver */
public class Main {
    public static void main(String[] args) throws Exception {
        ThreadPool pool = new ThreadPool(new PoolConfig(1, 1, 1, 1000));
        pool.setRejectionPolicy(new AbortPolicy());
        Task slow = new Task() {
            public String getName() { return "S"; }
            public void execute() { try { Thread.sleep(50); } catch (Exception e) {} }
        };
        pool.submit(slow); Thread.sleep(10); pool.submit(slow);
        try { pool.submit(slow); System.out.println("WRONG"); }
        catch (RuntimeException e) { System.out.println("OK_REJECTED"); }
        pool.shutdownNow();
    }
}

